import asyncio
import uuid
from dataclasses import dataclass, field
from datetime import datetime, UTC

@dataclass
class HighRiskApproval:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    tool_name: str = ""
    params: dict = field(default_factory=dict)
    tier: RiskTier = RiskTier.MEDIUM
    requested_by: str = ""      # agent or user identity
    approvals: list[str] = field(default_factory=list)   # approver IDs
    denial: str | None = None   # approver ID who denied
    created_at: datetime = field(default_factory=lambda: datetime.now(UTC))
    resolved_event: asyncio.Event = field(default_factory=asyncio.Event)

    @property
    def min_approvers(self) -> int:
        return TIER_MIN_APPROVERS[self.tier]

    @property
    def fully_approved(self) -> bool:
        if self.denial:
            return False
        # two-person rule: approver cannot be the requester
        valid = [a for a in self.approvals if a != self.requested_by]
        return len(valid) >= self.min_approvers

    @property
    def denied(self) -> bool:
        return self.denial is not None

_pending: dict[str, HighRiskApproval] = {}

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

class ApprovalAction(BaseModel):
    approver_id: str

@app.get("/approvals")
def list_approvals():
    return [
        {
            "id": r.id,
            "tool": r.tool_name,
            "tier": r.tier.name,
            "min_approvers": r.min_approvers,
            "approvals": r.approvals,
            "created_at": r.created_at.isoformat(),
        }
        for r in _pending.values()
    ]

@app.post("/approvals/{approval_id}/approve")
def approve(approval_id: str, body: ApprovalAction):
    req = _pending.get(approval_id)
    if not req:
        raise HTTPException(404, "Approval not found or already resolved")
    if body.approver_id == req.requested_by and req.tier == RiskTier.CRITICAL:
        raise HTTPException(403, "Two-person rule: requester cannot approve CRITICAL actions")
    if body.approver_id not in req.approvals:
        req.approvals.append(body.approver_id)
    if req.fully_approved:
        req.resolved_event.set()
    return {"status": "approved", "fully_approved": req.fully_approved}

@app.post("/approvals/{approval_id}/deny")
def deny(approval_id: str, body: ApprovalAction):
    req = _pending.get(approval_id)
    if not req:
        raise HTTPException(404, "Approval not found or already resolved")
    req.denial = body.approver_id
    req.resolved_event.set()
    return {"status": "denied"}
